+function isToolUseStreamResponse(chunk: StreamResponse): boolean {
+  const data = chunk.data as any;
+  return data?.type === "assistant" && Array.isArray(data?.message?.content) &&
+    data.message.content.some((item: any) => item.type === "tool_use");
+}
+
+/**
+ * Consume a nested agent without exposing its ordinary text in the chat room.
+ * Its text becomes the delegate_task result; nested tool calls and protocol
+ * errors still need to be visible to keep tool IDs/results auditable.
+ */
+async function collectNestedRun(
+  run: AsyncGenerator<StreamResponse, AgentRunResult>
+): Promise<{ result: AgentRunResult; stream: StreamResponse[] }> {
+  const stream: StreamResponse[] = [];
+  while (true) {
+    const next = await run.next();
+    if (next.done) return { result: next.value, stream };
+    if (next.value.type === "error" || isToolUseStreamResponse(next.value)) {
+      stream.push(next.value);
+    }
+  }
+}
+
+/** Run an agent, recursively satisfying delegate_task calls before resuming it. */
+async function* runAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  context: ProviderChatRequest["context"] = []
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    return { content: "", error: `Agent '${agentId}' not found or provider not available` };
+  }
+
+  let accumulatedText = "";
+  let toolSequence = 0;
+
+  while (true) {
+    const providerRequest: ProviderChatRequest = {
+      message: request.message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      context,
+    };
+    let delegated = false;
+
+    try {
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          const content = response.content || "";
+          accumulatedText += content;
+          yield { type: "claude_json", data: { type: "assistant", content, model: response.metadata?.model } };
+        } else if (response.type === "tool_use" && response.toolName === "delegate_task") {
+          const toolUseId = response.toolUseId || `${request.requestId}-delegate-${++toolSequence}`;
+          yield toolUseMessage(agentId, response, toolUseId, request.sessionId);
+
+          const input = response.toolInput as { agent_id?: unknown; instructions?: unknown } | undefined;
+          const delegatedAgentId = typeof input?.agent_id === "string" ? input.agent_id : "";
+          const instructions = typeof input?.instructions === "string" ? input.instructions : "";
+          let result: AgentRunResult;
+
+          if (!delegatedAgentId || !instructions) {
+            result = { content: "delegate_task requires string agent_id and instructions", error: "Invalid delegate_task input" };
+          } else if (delegationPath.includes(delegatedAgentId)) {
+            const error = `circular delegation detected: ${[...delegationPath, delegatedAgentId].join(" -> ")}`;
+            yield { type: "error", error };
+            result = { content: error, error };
+          } else if (!globalRegistry.getAgent(delegatedAgentId) || !globalRegistry.getProviderForAgent(delegatedAgentId)) {
+            const error = `Agent '${delegatedAgentId}' not found or provider not available`;
+            yield { type: "error", error };
+            result = { content: error, error };
+          } else {
+            const delegatedRequest: ChatRequest = { ...request, message: instructions };
+            const nested = await collectNestedRun(runAgentConversation(
+              delegatedAgentId, delegatedRequest, abortController, debugMode,
+              [...delegationPath, delegatedAgentId]
+            ));
+            for (const chunk of nested.stream) yield chunk;
+            result = nested.result;
+          }
+
+          const content = result.error
+            ? result.error
+            : result.content || `Sub-agent '${delegatedAgentId}' completed without textual output.`;
+          const toolResult: ToolResultPayload = {
+            type: "tool_result",
+            is_error: Boolean(result.error),
+            content,
+            tool_use_id: toolUseId,
+          };
+          context = [...context, { role: "user", content: JSON.stringify(toolResult) }];
+          delegated = true;
+          break;
+        } else if (response.type === "error") {
+          return { content: accumulatedText, error: response.error || "Agent run failed" };
+        }
+      }
+    } catch (error) {
+      return { content: accumulatedText, error: error instanceof Error ? error.message : String(error) };
+    }
+
+    if (!delegated) return { content: accumulatedText };
+  }
+}
